const leads = $input.first().json.leads;

const tierLabel = t => t === 'hot' ? '🔴 HOT' : '🟡 WARM';
const trackLabel = t => t === 'pre' ? 'Pre-market' : 'On-market';

const rows = leads.map(lead => {
  const trackDetails = lead.track === 'pre'
    ? `<tr><td colspan="2" style="padding:6px 8px;font-size:12px;color:#555;"><em>Timeline:</em> ${lead.pm_timeline || '-'} &nbsp;|&nbsp; <em>Price strategy:</em> ${lead.pm_price_strategy || '-'} &nbsp;|&nbsp; <em>Docs:</em> ${lead.pm_docs || '-'} &nbsp;|&nbsp; <em>Priority:</em> ${lead.pm_priority || '-'}</td></tr>`
    : `<tr><td colspan="2" style="padding:6px 8px;font-size:12px;color:#555;"><em>Offers:</em> ${lead.om_offers || '-'} &nbsp;|&nbsp; <em>Viewings:</em> ${lead.om_viewings || '-'} &nbsp;|&nbsp; <em>Price basis:</em> ${lead.om_price_basis || '-'} &nbsp;|&nbsp; <em>Changes:</em> ${lead.om_changes || '-'}</td></tr>`;

  return `
  <tr style="background:#fff8f0;">
    <td style="padding:10px 8px;font-weight:bold;white-space:nowrap;">${tierLabel(lead.lead_tier)} — ${trackLabel(lead.track)}</td>
    <td style="padding:10px 8px;">
      <strong>${lead.name || '-'}</strong> &nbsp;|&nbsp;
      ${lead.phone || '-'} &nbsp;|&nbsp;
      ${lead.email || '-'}
    </td>
  </tr>
  <tr>
    <td style="padding:4px 8px;font-size:12px;color:#555;">Lead score: ${lead.lead_quality_score}/100</td>
    <td style="padding:4px 8px;font-size:12px;color:#555;">${lead.property_type || ''} | ${lead.location || ''} ${lead.neighborhood || ''} | ${lead.area || ''}</td>
  </tr>
  <tr>
    <td style="padding:4px 8px;font-size:12px;color:#555;">Primary risk:</td>
    <td style="padding:4px 8px;font-size:12px;color:#c0272d;">${lead.primary_risk_agent || '-'}</td>
  </tr>
  ${trackDetails}
  <tr><td colspan="2" style="padding:4px 8px;font-size:11px;color:#999;">Submitted: ${lead.created_at ? new Date(lead.created_at).toLocaleString('bg-BG') : '-'} | ID: ${lead.id}</td></tr>
  <tr><td colspan="2" style="border-bottom:2px solid #e0e0e0;"></td></tr>
`;
}).join('');

const html = `
<div style="font-family:sans-serif;max-width:700px;">
  <h2 style="color:#c0272d;border-bottom:2px solid #c0272d;padding-bottom:8px;">⚠️ Reconciliation Alert — Missed Lead Notifications</h2>
  <p style="color:#555;">The following <strong>${leads.length}</strong> lead(s) were submitted but never notified — the real-time webhook likely failed. Review and follow up immediately.</p>
  <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;border:1px solid #ddd;">
    ${rows}
  </table>
  <p style="font-size:11px;color:#999;margin-top:16px;">Sent by Lead Reconciliation workflow · ${new Date().toISOString()}</p>
</div>
`;

return [{ json: { html, lead_ids: leads.map(l => l.id), count: leads.length } }];
